      END_STATE();
    case 23:
      ACCEPT_TOKEN(anon_sym_STAR);
      END_STATE();
    case 24:
      ACCEPT_TOKEN(anon_sym_PLUS);
      END_STATE();
    case 25:
      ACCEPT_TOKEN(anon_sym_AMP_AMP);
      END_STATE();
    case 26:
      ACCEPT_TOKEN(anon_sym_PIPE_PIPE);
      END_STATE();
    case 27:
      ACCEPT_TOKEN(anon_sym_DOTand_DOT);
      END_STATE();
    case 28:
      ACCEPT_TOKEN(anon_sym_DOTor_DOT);
      END_STATE();
    case 29:
      ACCEPT_TOKEN(anon_sym_DOTeqv_DOT);
      END_STATE();
    case 30:
      ACCEPT_TOKEN(anon_sym_DOTneqv_DOT);
      END_STATE();
    case 31:
